import { Schedule } from "./CoverageStatisticsSchedule/Schedule";
import styles from "./CoverageStatistics.module.css";
import { Button, Separator } from "@ui";
import { CoverageStatisticsProgress } from "./CoverageStatisticsProgress";
import { useQueryController } from "../../hooks/useQueryController";
import { useState } from "react";
import DatePicker from "react-datepicker";

const data = [
  {
    name: "07.12.2022",
    coverage: 0,
  },
  {
    name: "07.12.2022",
    coverage: 0.5,
  },
  {
    name: "07.12.2022",
    coverage: 1,
  },
  {
    name: "07.12.2022",
    coverage: 1.5,
  },
  {
    name: "07.12.2022",
    coverage: 2,
  },
];

interface CoverageStatisticsParamsType {
  allCoverage: number;
  coverage: number;
  percentile: number;
}

interface PredictParamsType {
  budgetSpent: number;
  clicks: number;
}

export const CoverageStatistics = () => {
  const { queryParams, setQueryParam } = useQueryController();

  const [coverageStatisticsParams, setCoverageStatisticsParams] =
    useState<CoverageStatisticsParamsType>();

  const [predict, setPredict] = useState<PredictParamsType>();

  const getCoverageStatistics = () => {
    const data = {
      target_groups: [
        ...(queryParams.deviceTypes
          ? [
              {
                type: "DEVICE_TYPE",
                values: queryParams.deviceTypes
                  .split(",")
                  .map((value) => Number(value)),
              },
            ]
          : []),
        ...(queryParams.regions
          ? [
              {
                type: "GEO",
                values: queryParams.regions
                  .split(",")
                  .map((value) => Number(value)),
              },
            ]
          : []),

        ...(queryParams.osVersions
          ? [
              {
                type: "DEVICE_OS",
                values: queryParams.osVersions
                  .split(",")
                  .map((value) => Number(value)),
              },
            ]
          : []),
        ...(queryParams.segments
          ? [
              {
                type: "DMP_SEGMENT",
                values: queryParams.segments
                  .split(",")
                  .map((value) => Number(value)),
              },
            ]
          : []),
      ],
      ...(queryParams.date ? { current_date: queryParams.date } : {}),
    };

    fetch("https://predictor-audience.adtech.rambler.ru/api/v1/coverage", {
      method: "post",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(data),
    })
      .then((response) => response.json())
      .then((data) =>
        setCoverageStatisticsParams({
          allCoverage: data.prediction.all_coverage,
          coverage: data.prediction.coverage,
          percentile: data.prediction.percentile,
        })
      );
  };

  const getPredict = () => {
    const data = {
      target_groups: [
        ...(queryParams.deviceTypes
          ? [
              {
                type: "DEVICE_TYPE",
                values: queryParams.deviceTypes
                  .split(",")
                  .map((value) => Number(value)),
              },
            ]
          : []),
        ...(queryParams.regions
          ? [
              {
                type: "GEO",
                values: queryParams.regions
                  .split(",")
                  .map((value) => Number(value)),
              },
            ]
          : []),

        ...(queryParams.osVersions
          ? [
              {
                type: "DEVICE_OS",
                values: queryParams.osVersions
                  .split(",")
                  .map((value) => Number(value)),
              },
            ]
          : []),
        ...(queryParams.segments
          ? [
              {
                type: "DMP_SEGMENT",
                values: queryParams.segments
                  .split(",")
                  .map((value) => Number(value)),
              },
            ]
          : []),
      ],
      ...(queryParams.date ? { current_date: queryParams.date } : {}),
    };

    fetch("https://predictor-audience.adtech.rambler.ru/api/v1/predict", {
      method: "post",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(data),
    })
      .then((response) => response.json())
      .then((data) =>
        setPredict({
          clicks: data.prediction.clicks,
          budgetSpent: data.prediction.budget_spent,
        })
      );
  };

  const [startDate, setStartDate] = useState(new Date());

  return (
    <div>
      <div className={styles.container}>
        <div className={styles.coverageCount}>
          <p>
            Охват аудитории <br />
            <span>{coverageStatisticsParams?.allCoverage}</span>
          </p>
        </div>
        <Schedule data={data} />
        <p className={styles.coverageStatus}>
          Потенциальный охват выбранной аудитории довольно широк!
        </p>
        <Separator />
        <CoverageStatisticsProgress
          name="Приблизительно за 7 дней"
          data={coverageStatisticsParams?.coverage || 0}
          fillingPercentage={coverageStatisticsParams?.percentile || 0}
        />
        <div>
          <p>Прогноз кликов</p>
          <p style={{ fontSize: "24px" }}>{predict?.clicks || 0}</p>
        </div>
        <div>
          <p>Рекомендация бюджета</p>
          <p style={{ fontSize: "24px" }}>
            {Math.round(predict?.budgetSpent || 0)}
          </p>
        </div>
      </div>
      <div className={styles.container} style={{ marginTop: "24px" }}>
        <DatePicker
          selected={startDate}
          onChange={(date) => {
            if (date) {
              setStartDate(date);
              setQueryParam("date", date.toISOString().split("T")[0]);
            }
          }}
        />
        <p style={{ marginBottom: "6px" }}>
          <input type="checkbox" />
          Окончательные данные
        </p>
        <Button
          name="Применить"
          textColor="white"
          onClick={() => {
            getCoverageStatistics();
            getPredict();
          }}
        />
      </div>
    </div>
  );
};
